import React from "react";
import { useNavigate, useLocation } from "react-router-dom";

export default function Sidebar() {
  const navigate = useNavigate();
  const location = useLocation();

  const menuItems = [
    { name: "Dashboard", path: "/dashboard", icon: "📊" },
    { name: "Contacts", path: "/contacts", icon: "👥" },
    { name: "Lead Management", path: "/leads", icon: "🎯" },
    { name: "Categories", path: "/categories", icon: "📁" },
    { name: "WhatsApp Blast", path: "/dashboard", icon: "💬" },
    { name: "SMS Blast", path: "/dashboard", icon: "📱" },
    { name: "Campaign History", path: "/campaign-history", icon: "📋" },
    { name: "Reports", path: "/reports", icon: "📈" },
    { name: "Settings", path: "/settings", icon: "⚙️" }
  ];

  const handleNavigation = (path) => {
    navigate(path);
  };

  const isActive = (path) => {
    return location.pathname === path;
  };

  return (
    <div className="w-64 h-screen bg-blue-900 text-white p-5">
      <h2 className="text-xl font-bold mb-8">CRM Dashboard</h2>
      <ul className="space-y-2">
        {menuItems.map((item) => (
          <li key={item.name}>
            <button
              onClick={() => handleNavigation(item.path)}
              className={`w-full text-left px-4 py-3 rounded-lg transition-colors duration-200 flex items-center gap-3 ${
                isActive(item.path)
                  ? "bg-blue-700 text-white"
                  : "hover:bg-blue-800 text-gray-300"
              }`}
            >
              <span className="text-lg">{item.icon}</span>
              <span>{item.name}</span>
            </button>
          </li>
        ))}
      </ul>
      
      <div className="absolute bottom-5 left-5 right-5">
        <div className="bg-blue-800 rounded-lg p-3">
          <div className="text-xs text-gray-400 mb-1">Quick Actions</div>
          <button
            onClick={() => handleNavigation("/dashboard")}
            className="w-full bg-green-600 hover:bg-green-700 text-white px-3 py-2 rounded text-sm font-medium transition-colors duration-200"
          >
            ➕ New Campaign
          </button>
        </div>
      </div>
    </div>
  );
}
